import{_ as a,o as s,c as n,a3 as l}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"11. Nauseous Work Allowance","description":"","frontmatter":{"title":"11. Nauseous Work Allowance","eba":"Health Allied & Managers Admin 2021-2025","topics":["allowances","employment"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/allowances/11-nauseous-work-allowance.md","filePath":"ebas/has-managers-admin/health-allied-services/allowances/11-nauseous-work-allowance.md"}'),t={name:"ebas/has-managers-admin/health-allied-services/allowances/11-nauseous-work-allowance.md"};function o(i,e,r,c,u,p){return s(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="_11-nauseous-work-allowance" tabindex="-1">11. Nauseous Work Allowance <a class="header-anchor" href="#_11-nauseous-work-allowance" aria-label="Permalink to &quot;11. Nauseous Work Allowance&quot;">​</a></h1><p>This clause does not apply to casual Employees</p><p><strong>11.1</strong> For the purpose of this clause 11, an Eligible Employee is an employee employed in the following classifications: • Allied Health Assistant • Laundry Hand • Anaesthetic Technician • Liver Transplant Technologist • Driver • Cleaner / Patient Transport • Dual Qualified Technician (Sterilising &amp; Assistant Operating Theatres) • Pathology Collector • Food and Domestic Services Assistant • Pathology Technician • General Services Supervisor • Patient Services Assistant • Health Care Worker • Patient Transport Officer • Hospital Attendant • Pharmacy Technician • Instrument Technician • Storeperson • Dual Qualified Technician • Security Officer • Laboratory Assistant • Theatre Technician</p><p><strong>11.2</strong> Eligible Employees will receive a Nauseous Allowance payment as follows: Amount (part time pro- Date rata) $350 FFPPOA 1 December 2021 $350 FFPPOA 1 December 2022 $350 FFPPOA 1 December 2023</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p>$350 FFPPOA 1 December 2024</p><p><strong>11.3</strong> Theatre Technicians</p><p><strong>(a)</strong> In addition to receiving the entitlement prescribed in subclause 11.2, an Employee classified as a Theatre Technician (including Liver Transplant Technologists and Dual Qualified Technicians) under <a href="/eba/ebas/has-managers-admin/schedules/2d-classification-structure-health-allied-services.html">Schedule 2D</a> will receive an additional $350 Nauseous Allowance payment as follows: Amount (part time pro- Date rata) $350 FFPPOA 1 July 2021 $350 FFPPOA 1 July 2022 $350 FFPPOA 1 July 2023 $350 FFPPOA 1 July 2024</p><p><strong>11.4</strong> This allowance is only payable on the above dates.</p><p>Plain language terms: unpleasant work allowance.</p>',10)])])}const m=a(t,[["render",o]]);export{d as __pageData,m as default};
